+const requestStatus = (target: URL): Promise<number> =>
+  new Promise((resolve, reject) => {
+    const req = http.request(
+      {
+        hostname: target.hostname,
+        port: target.port,
+        path: `${target.pathname}${target.search}`,
+        family: 4,
+        method: 'GET',
+      },
+      (res) => {
+        const status = res.statusCode ?? 0;
+        res.resume();
+        resolve(status);
+      }
+    );
+    req.on('error', reject);
+    req.end();
+  });

